    &attestation_hex,
    "0000000000000000000000000000000000000000",
    &input_data_bytes,
    None,
);
match verification_result {
    Ok(success) => Ok(encode(&[Token::Bool(success)])),
    Err(_) => Ok(encode(&[Token::Bool(false)])),
}
